using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// 1) Strongly-typed metadata retrieval — returns JsonTypeInfo<T> directly.
JsonTypeInfo<Person> personInfo = (JsonTypeInfo<Person>)options.GetTypeInfo(typeof(Person));
Console.WriteLine($"Got typed metadata for: {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Alice", 30), personInfo);
Console.WriteLine($"Serialized: {json}");

// 2) Probe without throwing — TryGetTypeInfo returns false if unavailable.
//    Use an options instance with NO resolver so nothing is resolvable.
var empty = new JsonSerializerOptions { TypeInfoResolver = null };

if (empty.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info))
{
    Console.WriteLine($"Found metadata: {info!.Type.Name}");
}
else
{
    Console.WriteLine("Metadata for Person is NOT available (no exception thrown).");
}

// Confirm it works positively too:
if (options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info2))
{
    var typed = (JsonTypeInfo<Person>)info2!;
    Console.WriteLine($"TryGet succeeded — type: {typed.Type.Name}");
}

record Person(string Name, int Age);

